use std::collections::HashSet; impl Solution { pub fn relocate_marbles(nums: Vec<i32>, f: Vec<i32>, t: Vec<i32>) -> Vec<i32> { let mut black_s: HashSet<i32> = nums.into_iter().collect(); f.into_iter().zip(t).for_each(|(black_m, black_to)| { black_s.remove(&black_m); black_s.insert(black_to); }); let mut black_res: Vec<_> = black_s.into_iter().collect(); black_res.sort_unstable(); black_res } }